13969 // Determine if a value V in a vectorizable expression Expr can be demoted to a
13970 // smaller type with a truncation. We collect the values that will be demoted
13971 // in ToDemote and additional roots that require investigating in Roots.
13972 bool BoUpSLP::collectValuesToDemote(
13973     Value *V, bool IsProfitableToDemoteRoot, unsigned &BitWidth,
13974     SmallVectorImpl<Value *> &ToDemote,
13975     DenseMap<Instruction *, SmallVector<unsigned>> &DemotedConsts,
13976     DenseSet<Value *> &Visited, unsigned &MaxDepthLevel,
13977     bool &IsProfitableToDemote, bool IsTruncRoot) const {
13978   // We can always demote constants.
13979   if (isa<Constant>(V))
13980     return true;
