13988   // by the insertelement instruction and not used in multiple vector nodes, it
13989   // cannot be demoted.
13990   // TODO: improve handling of gathered values and others.
13991   auto *I = dyn_cast<Instruction>(V);
13992   const TreeEntry *ITE = I ? getTreeEntry(I) : nullptr;
