6427 bool llvm::mayHaveNonDefUseDependency(const Instruction &I) {
6428   if (I.mayReadOrWriteMemory())
6429     // Memory dependency possible
6430     return true;
6431   if (!isSafeToSpeculativelyExecute(&I))
