6481 OverflowResult llvm::computeOverflowForSignedMul(const Value *LHS,
6482                                                  const Value *RHS,
6483                                                  const SimplifyQuery &SQ) {
6484   // Multiplying n * m significant bits yields a result of n + m significant
6485   // bits. If the total number of significant bits does not exceed the
6486   // result bit width (minus 1), there is no overflow.
6487   // This means if we have enough leading sign bits in the operands
6488   // we can guarantee that the result does not overflow.
6489   // Ref: "Hacker's Delight" by Henry Warren
6490   unsigned BitWidth = LHS->getType()->getScalarSizeInBits();
6491 
6492   // Note that underestimating the number of sign bits gives a more
6493   // conservative answer.
6494   unsigned SignBits =
6495       ::ComputeNumSignBits(LHS, 0, SQ) + ::ComputeNumSignBits(RHS, 0, SQ);
6496 
6497   // First handle the easy case: if we have enough sign bits there's
6498   // definitely no overflow.
6499   if (SignBits > BitWidth + 1)
6500     return OverflowResult::NeverOverflows;
6501 
6502   // There are two ambiguous cases where there can be no overflow:
6503   //   SignBits == BitWidth + 1    and
6504   //   SignBits == BitWidth
6505   // The second case is difficult to check, therefore we only handle the
6506   // first case.
6507   if (SignBits == BitWidth + 1) {
6508     // It overflows only when both arguments are negative and the true
6509     // product is exactly the minimum negative number.
6510     // E.g. mul i16 with 17 sign bits: 0xff00 * 0xff80 = 0x8000
6511     // For simplicity we just check if at least one side is not negative.
6512     KnownBits LHSKnown = computeKnownBits(LHS, /*Depth=*/0, SQ);
6513     KnownBits RHSKnown = computeKnownBits(RHS, /*Depth=*/0, SQ);
6514     if (LHSKnown.isNonNegative() || RHSKnown.isNonNegative())
6515       return OverflowResult::NeverOverflows;
6516   }
6517   return OverflowResult::MayOverflow;
6518 }
