6531 static OverflowResult
6532 computeOverflowForSignedAdd(const WithCache<const Value *> &LHS,
6533                             const WithCache<const Value *> &RHS,
6534                             const AddOperator *Add, const SimplifyQuery &SQ) {
6535   if (Add && Add->hasNoSignedWrap()) {
6536     return OverflowResult::NeverOverflows;
6537   }
6538 
6539   // If LHS and RHS each have at least two sign bits, the addition will look
6540   // like
6541   //
6542   // XX..... +
6543   // YY.....
6544   //
6545   // If the carry into the most significant position is 0, X and Y can't both
6546   // be 1 and therefore the carry out of the addition is also 0.
6547   //
6548   // If the carry into the most significant position is 1, X and Y can't both
6549   // be 0 and therefore the carry out of the addition is also 1.
6550   //
6551   // Since the carry into the most significant position is always equal to
6552   // the carry out of the addition, there is no signed overflow.
6553   if (::ComputeNumSignBits(LHS, 0, SQ) > 1 &&
6554       ::ComputeNumSignBits(RHS, 0, SQ) > 1)
6555     return OverflowResult::NeverOverflows;
6556 
6557   ConstantRange LHSRange =
6558       computeConstantRangeIncludingKnownBits(LHS, /*ForSigned=*/true, SQ);
6559   ConstantRange RHSRange =
6560       computeConstantRangeIncludingKnownBits(RHS, /*ForSigned=*/true, SQ);
6561   OverflowResult OR =
6562       mapOverflowResult(LHSRange.signedAddMayOverflow(RHSRange));
6563   if (OR != OverflowResult::MayOverflow)
6564     return OR;
6565 
6566   // The remaining code needs Add to be available. Early returns if not so.
6567   if (!Add)
6568     return OverflowResult::MayOverflow;
6569 
6570   // If the sign of Add is the same as at least one of the operands, this add
6571   // CANNOT overflow. If this can be determined from the known bits of the
6572   // operands the above signedAddMayOverflow() check will have already done so.
6573   // The only other way to improve on the known bits is from an assumption, so
6574   // call computeKnownBitsFromContext() directly.
6575   bool LHSOrRHSKnownNonNegative =
6576       (LHSRange.isAllNonNegative() || RHSRange.isAllNonNegative());
6577   bool LHSOrRHSKnownNegative =
6578       (LHSRange.isAllNegative() || RHSRange.isAllNegative());
6579   if (LHSOrRHSKnownNonNegative || LHSOrRHSKnownNegative) {
6580     KnownBits AddKnown(LHSRange.getBitWidth());
6581     computeKnownBitsFromContext(Add, AddKnown, /*Depth=*/0, SQ);
6582     if ((AddKnown.isNonNegative() && LHSOrRHSKnownNonNegative) ||
6583         (AddKnown.isNegative() && LHSOrRHSKnownNegative))
6584       return OverflowResult::NeverOverflows;
6585   }
6586 
6587   return OverflowResult::MayOverflow;
6588 }
